INSERT INTO `guanshangyubaike` (`id`,`addtime`,`zhongwenming`,`yingwenming`,`pinzhongfenlei`,`zhongshu`,`guanshangyutupian`,`zuixiaoshuiti`,`siyangnandu`,`chengtichicun`,`shanhugangjianrong`,`zhuyaochandi`,`guanshangyujianjie`,`storeupnum`,`shiwuyaoqiu`,`xingqing`,`yaoqiu`,`siyangfangfa`,`shengwujianjie`,`thumbsupnum`,`crazilynum`,`clicknum`) VALUES 
(1,'2026-04-23 06:53:18','血红龙鱼','Super Red Arowana','血红龙鱼','骨舌鱼科','upload/guanshangyubaike_jinlongyu_real.jpg','120cm缸以上','中等','60-80厘米','不兼容','印度尼西亚加里曼丹','亚洲龙鱼中最受欢迎的品种，全身鲜红色鳞片，被誉为风水鱼',12,'活食为主（小鱼、虾、昆虫），可驯食人工颗粒饲料','性情凶猛，领地意识极强。幼年期可混养，成鱼后需单独饲养。','大型水族箱建议180cm以上，pH 6.5-7.5，温度28-30℃，高效过滤系统。光照不宜过强。','每周换水20-30%。保持水质稳定。提供充足游动空间。幼鱼每日喂食2次，成鱼每日1次。定期检测氨氮和亚硝酸盐。','原产于印度尼西亚加里曼丹河流域，幼鱼鳞片银白色，2-3龄后发色呈鲜艳血红。成年体长60-80厘米，寿命20年以上。CITES公约附录I保护物种。',15,2,328),
(2,'2026-04-23 06:53:18','金龙鱼','Golden Arowana','金龙鱼','骨舌鱼科','upload/guanshangyubaike_jinlongyu_real.jpg','120cm缸以上','中等','60-80厘米','不兼容','马来西亚、印度尼西亚','亚洲龙鱼经典品种，以金色光泽闻名市场',10,'活食为主（小鱼、虾、蟋蟀），可驯食人工饲料','性情较为温顺但仍具领地意识，可与其他大型鱼类混养','大型水族箱建议180cm以上，pH 6.0-7.0，温度26-30℃，过滤系统须强大','保持弱酸性软水。提供底部躲避空间。以活食为主逐步驯化人工饲料。避免惊吓（易跳缸，缸盖必备）。','原产于东南亚，体色从淡金到24K纯金色不等，发色期约1-1.5龄。性情较红龙温和。极品个体价值可达数十万元。',12,1,256),
(3,'2026-04-23 06:53:18','月光鱼','Moon Platy','月光鱼','花鳉科','upload/guanshangyubaike_kongqueyu_real.jpg','30cm缸','简单','4-6厘米','兼容','中美洲（墨西哥、危地马拉）','新手入门最佳选择之一，体型小巧色彩丰富',6,'杂食性，人工饲料、红虫、水蚤、藻类','性情极其温和，是所有社区鱼缸的理想成员','小型水族箱30cm以上即可，pH 7.0-8.2，温度22-26℃，普通过滤','喜弱碱性硬水。群养效果更佳建议5条以上。繁殖极易，卵胎生。可与其他小型温和鱼类混养。','经过人工选育已有红黄蓝黑等多种颜色变种。卵胎生鱼类，雌鱼直接产出能自由游动的幼鱼。耐受力强，适合社区水族箱。',8,0,189),
(4,'2026-04-23 06:53:18','玛丽鱼','Black Molly','玛丽鱼','花鳉科','upload/guanshangyubaike_jinyu_real.jpg','40cm缸','简单','5-10厘米','兼容','中美洲至南美洲北部','非常受欢迎的中型观赏鱼，优秀的清缸工',5,'杂食性，人工饲料、藻类、红虫、水蚤','温和，喜群体活动，善于清理藻类','中型水族箱60cm以上，pH 7.5-8.5，温度24-28℃，可耐受一定盐度','偏好弱碱性硬水。可添加少量海盐每升水1-2克。需要植物覆盖的躲藏空间。繁殖为卵胎生。','体色以黑色为主，也有白金等多种变异。对水质适应性强甚至可在半咸水中生活。繁殖力强，卵胎生，适合初学者。',7,0,167),
(5,'2026-04-23 06:53:18','虎皮鱼','Tiger Barb','虎皮鱼','鲤科','upload/guanshangyubaike_landiaodiao.jpg','60cm缸','简单','5-7厘米','需注意混养','东南亚（苏门答腊、婆罗洲）','体侧四条黑色垂直条纹形似虎皮，游泳活跃的水族箱活力担当',7,'杂食性，人工饲料、红虫、水蚤、薄片','活跃好动，有轻微追咬习性，需要群养','中型水族箱60cm以上，pH 6.0-7.5，温度22-26℃','群养可减少互相攻击建议6条以上。避免与长鳍鱼类混养会咬鳍。提供开阔游动空间。杂食性，食谱可多样化。','经过人工选育已出现绿色、金色等变异品种。6条以上群体会表现出有趣的社会行为。不要与燕鱼、斗鱼等长鳍品种混养。',9,2,210),
(6,'2026-04-23 06:53:18','孔雀鱼','Guppy','孔雀鱼','花鳉科','upload/guanshangyubaike_kongqueyu_real.jpg','20cm缸','简单','3-6厘米','兼容','南美洲（委内瑞拉、圭亚那等地）','世界最流行观赏鱼之一，雄性绚丽多彩的尾鳍',15,'杂食性，人工饲料、红虫、水蚤、丰年虾','非常温和，完美的社区鱼缸成员','小型水族箱20cm以上，pH 7.0-8.0，温度22-28℃','水质适应性强。繁殖力极强，卵胎生。注意控制雌雄比例建议1雄配3雌。幼鱼需隔离饲养或提供水草遮蔽。避免强水流。','经过百年人工选育已有数百个品系，尾鳍形态有圆尾、剑尾、扇尾、冠尾等。28天左右可生产一胎，每胎20-100条。遗传学经典模式生物。',22,0,489),
(7,'2026-04-23 06:53:18','招财鱼','Parrot Cichlid','招财鱼','慈鲷科','upload/guanshangyubaike_leilongyu.jpg','200cm缸','中等','20-30厘米','部分兼容','东南亚、南美洲（人工杂交种）','体形圆润游动姿态优雅，在华人文化中寓意招财进宝',8,'杂食性，人工饲料、红虫、虾肉、蔬菜','温和但具领地意识，可与同等体型鱼类混养','大型水族箱120cm以上，pH 6.5-7.5，温度24-28℃','提供足够的游动空间。可喂食人工慈鲷颗粒饲料。定期换水保持水质。可混养但避免与攻击性强的鱼类共处。注意观察体色变化（健康状况指标）。','实际为多种慈鲷的人工杂交品种，颜色以红、橙、黄为主。性情相对温和，适合作为大型观赏鱼入门品种。',11,1,234),
(8,'2026-04-23 06:53:18','罗汉鱼','Flowerhorn Cichlid','罗汉鱼','慈鲷科','upload/guanshangyubaike_jinli.jpg','200cm缸','中等','20-35厘米','不兼容','马来西亚、泰国（人工杂交品种）','头部巨大的肉瘤为标志性特征，极具个性',11,'杂食性，偏好高蛋白饲料（虾、鱼肉、专用颗粒）','性情凶猛，领地意识极强，只能单独饲养','大型水族箱120cm以上，pH 7.0-8.0，温度28-32℃，高效过滤','必须单独饲养。高蛋白饲料促进头部肉瘤发育。保持较高水温28-32℃。每周换水30%。提供镜子和玩具刺激互动。','20世纪90年代在东南亚人工培育的品种。肉瘤大小受基因、营养、水质等因素影响。能与主人互动甚至从手中接食。',18,3,356),
(9,'2026-05-01 10:00:00','蓝倒吊','Blue Tang','蓝倒吊','刺尾鱼科','upload/guanshangyubaike_landiaodiao.jpg','300cm缸','高','20-30厘米','部分兼容','印度洋、太平洋热带海域','因电影《海底总动员》多莉角色而家喻户晓',14,'植食性为主，海藻、螺旋藻薄片、冷冻丰年虾','较为温和，但同种间有竞争，建议单条或群养','大型海水缸200cm以上，pH 8.1-8.4，盐度1.020-1.025，温度24-28℃','需要大型成熟海水缸。喂食多样化藻类食物。提供躲避空间和开阔游动区域。注意预防白点病。定期检测水质参数钙镁碱度。','身体呈鲜艳宝蓝色，尾鳍亮黄色，尾部两侧各有一根锋利倒刺为防御武器。对水质变化敏感，容易感染海水白点病。',25,5,198),
(10,'2026-05-01 10:00:00','锦鲤','Nishikigoi','锦鲤','鲤科','upload/guanshangyubaike_jinli.jpg','500升以上','中等','30-90厘米','兼容（温带淡水）','日本（人工选育品种，祖先为普通鲤鱼）','日本国鱼，根据颜色和斑纹分为红白、大正三色等多个品系',16,'杂食性，专用锦鲤颗粒饲料、红虫、虾、蔬菜','性情温和，适合与其他锦鲤或大型温和鱼类混养','池塘或超大型缸建议300cm以上，pH 7.0-8.0，温度15-25℃','需要充足水体和强劲过滤系统。不要与小型鱼类混养。冬季降低喂食频率。定期检测氨氮和亚硝酸盐。提供足够游动空间。','经过200多年人工选育，具有极高观赏价值。一条顶级锦鲤可价值数十万元。寿命极长有的可达70年。在亚洲文化中象征坚韧和成功。',20,0,278),
(11,'2026-05-01 10:00:00','小丑鱼','Clownfish','小丑鱼','雀鲷科','upload/guanshangyubaike_xiaochouyu.jpg','100cm缸','中等','5-12厘米','兼容（珊瑚缸）','印度洋、太平洋热带珊瑚礁海域','因电影《海底总动员》尼莫形象闻名世界',22,'杂食性，人工海水鱼颗粒、冷冻丰年虾、藻类薄片','温和，与海葵共生，领域性较强','中小型海水缸60cm以上，pH 8.1-8.4，盐度1.020-1.025，温度24-28℃','最好配一只海葵地毯海葵或奶嘴海葵。一缸只养一对或一小群。喂食多样化。幼鱼可多餐少喂。注意海水鱼常见疾病预防。','体色鲜艳橙白相间，黑色条纹勾勒出独特轮廓。对小丑鱼来说海葵毒刺免疫，在海葵触手中获得保护。雌雄同体，幼鱼全为雄性。',32,1,567),
(12,'2026-05-01 10:00:00','暹罗斗鱼','Betta','斗鱼','丝足鲈科','upload/guanshangyubaike_douyu.jpg','5升以上','简单','5-8厘米','不兼容同类雄鱼','东南亚（泰国、柬埔寨、越南）','观赏鱼界的格斗士，拥有华丽的鳍型和斑斓色彩',18,'肉食性，专用斗鱼饲料、红虫、水蚤、丰年虾','雄性之间极度好斗，需单独饲养','小型容器5升以上，pH 6.8-7.5，温度24-30℃','雄性必须单独饲养。容器不要太深因需水面换气。水温不宜低于22℃易得病。可展示镜子刺激鳍部发育。每天喂食1-2次。','经过数百年人工选育已培育出半月、冠尾、双尾等数十个品系，颜色覆盖红蓝绿紫白等全色谱。属迷鳃鱼可直接呼吸空气。',16,1,445),
(13,'2026-05-01 10:00:00','雷龙鱼','Snakehead Fish','雷龙鱼','鳢科','upload/guanshangyubaike_leilongyu.jpg','300cm缸','高','30-100厘米','不兼容','东南亚、南亚、非洲','观赏鱼中的终极挑战，顶级淡水捕食者',6,'肉食性，活鱼、虾、昆虫、人工驯食饲料','极度凶猛，只能单独饲养','超大型缸200cm以上，pH 6.5-7.5，温度24-30℃，加盖牢固的缸盖','必须单独饲养会攻击一切能吞下的生物。缸盖必须牢固跳跃能力极强。换水时注意安全攻击性极强。需要强大循环过滤系统。喂食活食需注意疾病带入风险。','属于鳢科，部分品种体长可达1米以上。拥有强壮的身体和巨大的嘴。具有特殊的迷鳃器官可在低氧水中生存。游动极具力量感观赏性十足。',9,2,167);
